import random

def _partition(arr, low, high):
    pivot = arr[high]
    i = low - 1
    for j in range(low, high):
        if arr[j] <= pivot:
            i += 1
            arr[i], arr[j] = arr[j], arr[i]
    arr[i + 1], arr[high] = arr[high], arr[i + 1]
    return i + 1

def quick_sort_recursive(arr, low=0, high=None):
    if high is None:
        high = len(arr) - 1

    if low < high:
        pi = _partition(arr, low, high)
        quick_sort_recursive(arr, low, pi - 1)
        quick_sort_recursive(arr, pi + 1, high)

def quick_sort_iterative(arr):
    if not arr or len(arr) < 2:
        return

    stack = []
    stack.append((0, len(arr) - 1))

    while stack:
        low, high = stack.pop()

        if low < high:
            pi = _partition(arr, low, high)

            # Push sub-arrays to stack
            # Process right sub-array first to mimic recursive call order if desired,
            # or simply push both. Order doesn't affect correctness but can impact stack depth.
            if pi + 1 < high:
                stack.append((pi + 1, high))
            if low < pi - 1:
                stack.append((low, pi - 1))
